#include<bits/stdc++.h>
#define ll long long
using namespace std;
int a,b,c[100005],d,e;
int f,g,h;
map<int,int> i;
int main(){
    cin.tie(0);
    ios::sync_with_stdio(false);
    cin>>a>>b;
    i[0]=0;
    for(int j=1;j<=a;j++){
        cin>>c[j];
        d=(e+c[j])%b;
        e=d;
        if(i.count(d)){
            if(j-i[d]>=f){
                f=j-i[d];
                g=i[d]+1;
                h=j;
            }
        }else{
            i[d]=j;
        }
    }
    if(f==0){
        cout<<"-1";
        return 0;
    }
    cout<<f<<"\n";
    for(int j=g;j<=h;j++) cout<<c[j]<<" ";
    return 0;
}
